import { useEffect, useMemo, useState } from 'react';
import AdminSidebar from '../components/layout/AdminSidebar';
import Loader from '../components/common/Loader';
import { useToast } from '../components/common/ToastProvider';
import { fetchUsers, fetchPendingDonors, verifyDonor, addHospital, removeHospital } from '../api/admin.api';
import { fetchAdminAlerts } from '../api/sos.api';
import { fetchHospitals } from '../api/hospitals.api';

function AdminDashboard() {
  const [active, setActive] = useState('users');
  const [loading, setLoading] = useState(true);
  const [users, setUsers] = useState([]);
  const [pendingDonors, setPendingDonors] = useState([]);
  const [hospitals, setHospitals] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [hospitalForm, setHospitalForm] = useState({ name: '', city: '', address: '', phone: '' });
  const { pushToast } = useToast();

  const loadAll = async () => {
    try {
      setLoading(true);
      const [u, d, h, a] = await Promise.all([
        fetchUsers().catch(() => []),
        fetchPendingDonors().catch(() => []),
        fetchHospitals().catch(() => []),
        fetchAdminAlerts().catch(() => [])
      ]);

      setUsers(u.length ? u : [
        { id: 1, name: 'Anita', email: 'anita@mail.com', role: 'USER' },
        { id: 2, name: 'Suresh', email: 'suresh@mail.com', role: 'ADMIN' }
      ]);
      setPendingDonors(d.length ? d : [
        { id: 11, name: 'Ramesh', bloodGroup: 'O+', city: 'Hyderabad' }
      ]);
      setHospitals(h.length ? h : [
        { id: 21, name: 'CityCare ER', city: 'Hyderabad', address: 'MG Road', phone: '040-2100-1234' }
      ]);
      setAlerts(a.length ? a : [
        { id: 31, userId: 1, location: 'Madhapur', createdAt: new Date().toISOString(), status: 'OPEN' }
      ]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAll();
  }, []);

  const verify = async (id) => {
    try {
      await verifyDonor(id);
      setPendingDonors((prev) => prev.filter((d) => d.id !== id));
      pushToast('Donor verified.', 'success');
    } catch {
      pushToast('Verification endpoint unavailable. Updated locally.', 'warning');
      setPendingDonors((prev) => prev.filter((d) => d.id !== id));
    }
  };

  const addHospitalEntry = async (e) => {
    e.preventDefault();
    if (!hospitalForm.name || !hospitalForm.city) return;
    try {
      await addHospital(hospitalForm);
      pushToast('Hospital added.', 'success');
    } catch {
      pushToast('Hospital API unavailable. Added locally.', 'warning');
    }
    setHospitals((prev) => [...prev, { ...hospitalForm, id: Date.now() }]);
    setHospitalForm({ name: '', city: '', address: '', phone: '' });
  };

  const deleteHospitalEntry = async (id) => {
    try {
      await removeHospital(id);
      pushToast('Hospital removed.', 'success');
    } catch {
      pushToast('Delete API unavailable. Removed locally.', 'warning');
    }
    setHospitals((prev) => prev.filter((h) => h.id !== id));
  };

  const content = useMemo(() => {
    if (active === 'users') {
      return (
        <div className='card card-soft p-3'>
          <h5>Users</h5>
          <div className='table-responsive'>
            <table className='table align-middle'>
              <thead><tr><th>ID</th><th>Name</th><th>Email</th><th>Role</th></tr></thead>
              <tbody>
                {users.map((u) => (
                  <tr key={u.id}><td>{u.id}</td><td>{u.name}</td><td>{u.email}</td><td>{u.role}</td></tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      );
    }

    if (active === 'donors') {
      return (
        <div className='card card-soft p-3'>
          <h5>Donor Verification</h5>
          {pendingDonors.length === 0 && <p className='text-muted mb-0'>No pending donors.</p>}
          <div className='row g-2'>
            {pendingDonors.map((d) => (
              <div className='col-md-6' key={d.id}>
                <div className='border rounded p-2'>
                  <p className='mb-1 fw-semibold'>{d.name} ({d.bloodGroup})</p>
                  <p className='mb-2 text-muted'>{d.city}</p>
                  <button className='btn btn-sm btn-danger' onClick={() => verify(d.id)}>Verify</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      );
    }

    if (active === 'hospitals') {
      return (
        <div className='card card-soft p-3'>
          <h5>Hospital Management</h5>
          <form className='row g-2 mb-3' onSubmit={addHospitalEntry}>
            <div className='col-md-3'><input className='form-control' placeholder='Name' value={hospitalForm.name} onChange={(e) => setHospitalForm((p) => ({ ...p, name: e.target.value }))} /></div>
            <div className='col-md-2'><input className='form-control' placeholder='City' value={hospitalForm.city} onChange={(e) => setHospitalForm((p) => ({ ...p, city: e.target.value }))} /></div>
            <div className='col-md-3'><input className='form-control' placeholder='Address' value={hospitalForm.address} onChange={(e) => setHospitalForm((p) => ({ ...p, address: e.target.value }))} /></div>
            <div className='col-md-2'><input className='form-control' placeholder='Phone' value={hospitalForm.phone} onChange={(e) => setHospitalForm((p) => ({ ...p, phone: e.target.value }))} /></div>
            <div className='col-md-2 d-grid'><button className='btn btn-danger'>Add Hospital</button></div>
          </form>

          <div className='table-responsive'>
            <table className='table align-middle'>
              <thead><tr><th>Name</th><th>City</th><th>Contact</th><th /></tr></thead>
              <tbody>
                {hospitals.map((h) => (
                  <tr key={h.id}>
                    <td>{h.name}</td>
                    <td>{h.city}</td>
                    <td>{h.phone || 'N/A'}</td>
                    <td><button className='btn btn-sm btn-outline-danger' onClick={() => deleteHospitalEntry(h.id)}>Delete</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      );
    }

    return (
      <div className='card card-soft p-3'>
        <h5>SOS Monitoring</h5>
        <div className='table-responsive'>
          <table className='table align-middle'>
            <thead><tr><th>Alert ID</th><th>User</th><th>Location</th><th>Status</th><th>Time</th></tr></thead>
            <tbody>
              {alerts.map((a) => (
                <tr key={a.id}>
                  <td>#{a.id}</td>
                  <td>{a.userId}</td>
                  <td>{a.location}</td>
                  <td><span className='badge text-bg-warning'>{a.status || 'OPEN'}</span></td>
                  <td>{new Date(a.createdAt).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  }, [active, users, pendingDonors, hospitals, alerts, hospitalForm]);

  if (loading) {
    return <Loader label='Loading admin dashboard...' />;
  }

  return (
    <div className='container py-4'>
      <h2 className='mb-3'>Admin Dashboard</h2>
      <div className='row g-3'>
        <div className='col-lg-3'>
          <AdminSidebar active={active} onChange={setActive} />
        </div>
        <div className='col-lg-9'>
          {content}
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
